const tabs=[...document.querySelectorAll(".tab")],panels=[...document.querySelectorAll(".tab-panel")];function setActiveTab(t){tabs.forEach(e=>e.classList.toggle("is-active",e.dataset.tab===t)),panels.forEach(e=>e.classList.toggle("is-active",e.id===t))}tabs.forEach(t=>{t.addEventListener("click",()=>setActiveTab(t.dataset.tab))});const lazySections=document.querySelectorAll(".lazy-section");if("IntersectionObserver"in window){const t=new IntersectionObserver((e,o)=>{e.forEach(e=>{e.isIntersecting&&(e.target.classList.add("loaded"),o.unobserve(e.target))})},{rootMargin:"250px 0px"});lazySections.forEach(e=>t.observe(e))}else lazySections.forEach(t=>t.classList.add("loaded"));function updateDateTime(){const t=new Date,e=document.getElementById("date"),a=document.getElementById("time"),o=document.getElementById("current-year"),n={weekday:"short",year:"numeric",month:"short",day:"numeric"},i={hour:"2-digit",minute:"2-digit",second:"2-digit",hour12:!0,timeZone:"Asia/Kolkata"};e&&(e.textContent=t.toLocaleDateString("en-IN",n)),a&&(a.textContent=`${t.toLocaleTimeString("en-IN",i)} IST`),o&&(o.textContent=String(t.getFullYear()))}updateDateTime(),setInterval(updateDateTime,1e3);const mainCta=document.querySelector(".main-cta");mainCta&&mainCta.addEventListener("click",t=>{t.preventDefault(),setActiveTab("contact");const e=document.querySelector("#contact-panel");e&&e.scrollIntoView({behavior:"smooth",block:"center"})});
